insert into public.products (id, category, name, "basePrice", cost, rating, reviews, "desc", detail, dims, material, images, "reviewNote", highlights, discounts) values
  ('p1', 'desk', '가구느낌 베스트 책상', 24900, 11000, 4.6, 3425, '군더더기 없는 기본형 책상, 좁은 방에도 잘 맞아요', '꾸밈없는 사각 책상이라 어떤 방에도 무난하게 어울려요. 모니터·노트북에 책 몇 권 올려두기 충분한 넓이라 자취 첫 책상으로 부담 없어요.', 'W1000×D500×H730mm', 'PB, 친환경 E1등급', '["","","",""]'::jsonb, '철제 다리 책상은 흔들림 없이 안정적이고 혼자서도 쉽게 조립된다는 평이 많아요. 다만 서랍이 따로 없어 별도 수납을 함께 준비하는 걸 추천해요.', '["흔들림 없는 안정감","혼자서도 빠른 조립","어디에나 어울리는 디자인"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p2', 'desk', 'Sonipure 수납선반 컴퓨터 책상', 42800, 19000, 4.5, 979, '옆면 수납 선반이 있어 책이나 소품 정리가 편해요', '상판 위로 수납 선반이 한 단 더 있어서 책이나 모니터 받침대를 따로 안 사도 돼요. 짐이 많은 편이면 이쪽을 추천해요.', 'W1000×D500×H1000mm (선반 포함)', 'MDF + 메탈 프레임', '["","","",""]'::jsonb, '위에 수납 선반이 있는 책상은 모니터 받침이나 책 정리가 한결 편하다는 후기가 많아요. 조립에 1시간 정도 걸린다는 의견도 있어요.', '["수납 선반 한 단 추가","넉넉한 책상 면적","모니터 받침 따로 불필요"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p3', 'desk', 'GERDU 전동 높이조절 모션데스크', 116900, 58000, 4.4, 33, '버튼 하나로 높이를 바꾸는 책상, 앉아서도 서서도 작업해요', '버튼으로 높이를 바꿔서 앉아서도 서서도 작업할 수 있어요. 장시간 책상 앞에 있는 직무라면 가격 이상의 값을 해요.', 'W1200×D600×H700~1200mm (높이조절)', '스틸 프레임 + MDF 상판', '["","","",""]'::jsonb, '전동 높이조절 책상은 앉아서/서서 작업을 오갈 수 있어 만족도가 높다는 평이 많고, 케이블 정리가 깔끔해진다는 의견도 있어요. 다만 일반 책상보다 가격대가 있어 꼭 필요한 사람에게 추천한다는 의견이에요.', '["전동 높이조절","앉아서·서서 모두 작업","깔끔한 케이블 정리"]'::jsonb, '[0,8,15,25]'::jsonb),
  ('p4', 'chair', '티야드 자세교정 메쉬 사무용 의자', 38900, 17000, 4.6, 4960, '허리 받침이 있는 메쉬 의자, 장시간 앉아도 편안해요', '허리 받침이 도드라져서 장시간 앉아도 자세가 무너지지 않아요. 가성비 사무용 의자 중에서는 꾸준히 검증된 제품이에요.', 'W620×D620×H1000~1080mm', '메쉬 + 나일론 다리', '["","","",""]'::jsonb, '메쉬 등받이라 여름에도 땀이 덜 차고 통풍이 잘 된다는 평이 많고, 허리 받침 덕분에 오래 앉아도 편하다는 후기가 많아요.', '["통풍 잘 되는 메쉬","허리 받침 내장","장시간 착석에 강함"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p5', 'chair', 'FONOW 메쉬 독서실 의자', 31940, 14000, 4.4, 186, '바퀴 없이 안정적인 학습용 의자예요', '바퀴가 없어 흔들림이 적고, 좁은 책상 밑에 깔끔하게 들어가요. 공부용 의자로 적당해요.', 'W550×D550×H950~1020mm', '메쉬 + 스틸 프레임', '["","","",""]'::jsonb, '바퀴 없는 독서실 의자는 흔들림이 적고 좁은 책상 밑에도 잘 들어간다는 평이 많아요. 디자인이 단정해서 학습 공간에 잘 어울린다는 의견도 있어요.', '["바퀴 없는 안정형","좁은 책상 밑 수납","단정한 학습용 디자인"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p6', 'chair', 'HOMEY NEST 풀메쉬 게이밍 의자', 139900, 65000, 4.6, 1890, '통풍이 잘 되는 풀메쉬 소재의 인체공학 의자', '등받이 전체가 메쉬라 여름에도 덜 답답하고, 허리·목 받침까지 있어요. 의자에 오래 앉아 있는 게임·작업러에게 좋아요.', 'W680×D700×H1200~1280mm', '풀메쉬 + 알루미늄 베이스', '["","","",""]'::jsonb, '풀메쉬 의자는 여름철 장시간 사용에도 답답하지 않다는 평이 많고, 요추받침·팔걸이 조절이 세밀해서 체형에 맞추기 좋다는 후기가 있어요. 다만 흔들림 없이 쓰려면 평평한 바닥에 두는 게 좋다는 의견도 있어요.', '["풀메쉬 통풍","요추·팔걸이 다중 조절","장시간 게임·작업용"]'::jsonb, '[0,8,15,25]'::jsonb),
  ('p7', 'bed', 'KURUA 슈퍼싱글 독립스프링 매트리스', 69800, 32000, 4.7, 9999, '독립 스프링이라 옆사람 뒤척임이 덜 느껴져요', '스프링이 따로따로 움직여서 옆 사람이 뒤척여도 덜 흔들려요. 첫 자취 매트리스로 무난한 두께예요.', 'W1100×L2000×H200mm (슈퍼싱글)', '독립 포켓스프링 + 메모리폼 토퍼', '["","","",""]'::jsonb, '독립스프링 매트리스는 옆 사람이 뒤척여도 진동이 덜 전달되고 몸의 곡선을 잘 받쳐준다는 평이 많아요. 본넬 스프링보다는 가격이 있지만 자취생도 많이 선택하는 타입이에요.', '["독립 스프링 방진동","메모리폼 토퍼","자취 첫 매트리스로 무난"]'::jsonb, '[0,8,15,25]'::jsonb),
  ('p8', 'bed', 'KURUA 무설치 접이식 야전침대', 34800, 15000, 4.5, 2063, '쓸 때만 펼치는 휴대용 침대, 손님용으로도 좋아요', '조립 없이 펼치기만 하면 돼서 이사 당일에도 바로 잘 수 있어요. 손님용으로 접어 보관하기도 좋아요.', '펼침 W900×L1950×H350mm / 접으면 1/3 크기', '옥스포드 원단 + 알루미늄 프레임', '["","","",""]'::jsonb, '이사할 때 침대를 새로 들이기 부담스러워 접이식 침대를 골랐다는 후기가 많고, 자리를 많이 차지하지 않으면서도 누웠을 때 안정적이라는 평이 많아요. 가벼운 삐걱임이 있을 수 있다는 의견도 있어요.', '["무설치 즉시 사용","1/3 크기로 접힘","손님용으로도 활용"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p9', 'wardrobe', '대용량 자취방 커튼형 간이옷장', 12900, 5000, 4.3, 108, '커튼형이라 가벼운 옷 보관에 적당, 작은 방에 딱이에요', '조립이 간단하고 가벼운 옷·계절옷 보관에 충분해요. 정식 옷장을 들이기 전 임시용으로도 좋아요.', 'W1050×D450×H1700mm', '철제 프레임 + 부직포 커튼', '["","","",""]'::jsonb, '커튼형 옷장은 조립이 간단하고 가벼운 옷·계절옷 보관에 충분하다는 평이 많아요. 본격적인 옷장을 들이기 전 임시 수납으로 추천하는 의견이 많아요.', '["조립 5분 완성","계절옷 보관에 적합","임시 수납으로 추천"]'::jsonb, '[0,12,25,35]'::jsonb),
  ('p10', 'wardrobe', '모던홈 시스템 드레스룸 옷장', 59900, 27000, 4.4, 157, '행거와 선반을 같이 써서 옷과 잡화를 정리해요', '행거 구역과 선반 구역이 같이 있어서 옷과 가방·잡화를 나눠 정리할 수 있어요. 짐이 많은 편이면 이쪽이 더 오래 쓰기 좋아요.', 'W1500×D450×H1700mm', '철제 프레임 + 선반/행거봉', '["","","",""]'::jsonb, '시스템 행거형 옷장은 사각 프레임이라 코트나 패딩을 가득 걸어도 잘 휘지 않는다는 평이 많아요. 흔들린다는 후기는 대부분 바닥 수평이 안 맞은 경우라, 하단 조절발로 수평을 맞추면 안정적이라는 팁이 많아요.', '["사각 프레임 내구성","행거+선반 동시 수납","수평 조절 발 포함"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p11', 'drawer', '코멧 모던 슬림 서랍장 3단', 13970, 5800, 4.7, 16326, '좁은 틈새에도 들어가는 슬림한 3단 서랍장', '폭이 좁아서 침대와 벽 사이 같은 좁은 틈에도 들어가요. 속옷·양말 같은 작은 짐 정리에 딱이에요.', 'W340×D280×H600mm', 'PB + ABS 손잡이', '["","","",""]'::jsonb, '이중 레일 구조라 서랍이 부드럽게 열리고 잘 안 빠진다는 평이 많고, 가벼워서 서랍장 밑이나 뒤를 청소하기도 편하다는 후기가 많아요. 속옷·양말 같은 작은 짐 정리에 좋다는 의견이 많아요.', '["좁은 틈새에 쏙","이중 레일 부드러운 개폐","가벼워 청소 편리"]'::jsonb, '[0,12,25,35]'::jsonb),
  ('p12', 'drawer', '스마트 이동식 3단 서랍장', 43900, 19500, 4.5, 860, '책상 옆에 붙여 쓰는 바퀴 달린 서랍장', '바퀴가 달려 있어 책상 옆이나 침대 밑으로 밀어 넣기 편해요. 책상 서랍이 부족할 때 보충용으로 좋아요.', 'W400×D450×H650mm', 'PB + 캐스터(바퀴)', '["","","",""]'::jsonb, '바퀴가 달려 있어 책상 옆이나 침대 밑으로 밀어 넣기 편하다는 평이 많고, 서랍이 추가돼 수납이 넉넉해졌다는 후기가 많아요.', '["바퀴로 이동 자유","책상 옆 보조 수납","조립 간단"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p13', 'bookshelf', '아이리스 오픈형 책장 3단', 15900, 6500, 4.6, 3453, '오픈형이라 책 꺼내기 편하고 가벼워서 옮기기도 쉬워요', '가벼워서 혼자 옮기기 쉽고, 칸이 트여 있어 책을 눕혀 쌓아도 답답해 보이지 않아요.', 'W600×D260×H880mm', 'PP(폴리프로필렌)', '["","","",""]'::jsonb, 'PP 소재 오픈형 책장은 가볍고 조립이 거의 필요 없어 혼자 옮기기 쉽다는 평이 많아요. 모서리가 살짝 거칠 수 있어 모서리가드를 추가하는 사람도 있어요.', '["PP 소재로 가벼움","조립 거의 불필요","오픈형 손쉬운 정리"]'::jsonb, '[0,12,25,35]'::jsonb),
  ('p14', 'bookshelf', '가구느낌 리버 책장 5단', 47900, 21000, 4.6, 3803, '5단으로 수납량이 넉넉한 책장이에요', '5단이라 책뿐 아니라 작은 짐 박스까지 같이 올려둘 수 있어요. 책이 많은 전공이라면 추천해요.', 'W600×D250×H1500mm', 'PB, 친환경 E1등급', '["","","",""]'::jsonb, '5단 구성이라 책뿐 아니라 잡동사니 박스까지 같이 올려둘 수 있어 수납량에 만족한다는 평이 많아요. 오픈형이라 정리 상태가 그대로 보이니 깔끔하게 꽂아두는 걸 추천해요.', '["5단 대용량 수납","친환경 E1 등급 자재","오픈형 진열 수납"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p15', 'table', '헤르티만 레트로 4인용 식탁', 49800, 22000, 4.4, 399, '2~4인이 같이 쓰기 좋은 접이식 식탁', '혼자 살아도 책상 겸 식탁으로 쓰기 좋은 크기예요. 친구들이 자주 놀러 오는 자취방이면 넉넉해서 좋아요.', 'W1200×D700×H750mm (4인용)', 'LPM(멜라민) 상판 + 철제 다리', '["","","",""]'::jsonb, '접이식 식탁은 안 쓸 때 접어두면 방이 넓어 보이고, 책이나 비상약 같은 물건을 수납할 공간도 있어 만족한다는 평이 많아요. 스틸 다리·경첩이 있어 접이식치고 튼튼하다는 의견도 많아요.', '["접이식으로 공간 절약","스틸 다리·경첩 견고","최대 4인까지"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p16', 'table', '업그레이드 주방 수납 테이블', 65510, 30000, 4.5, 1368, '전자레인지나 그릇을 올려두는 주방용 수납 테이블', '전자레인지·그릇을 올려두는 동시에 아래 칸에 식자재나 냄비를 수납할 수 있어요. 주방이 좁은 원룸에 특히 유용해요.', 'W900×D450×H850mm (3단)', '스틸 프레임 + PE 선반', '["","","",""]'::jsonb, '주방 수납 테이블은 전자레인지나 그릇을 올리면서 아래 칸에 식자재를 정리할 수 있어 좁은 주방에 유용하다는 평이 많아요.', '["3단 주방 수납","전자레인지 거치 가능","좁은 주방에 최적화"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p17', 'nightstand', 'Kurua 원목 2단 서랍 협탁', 26800, 11500, 4.6, 1752, '침대 옆에 두기 좋은 2단 서랍 협탁', '침대 옆에 두면 충전기·안경·책 한 권 정도를 정리하기 좋은 높이예요. 우드 톤이라 어떤 인테리어에도 무난해요.', 'W400×D350×H500mm', '원목 + MDF', '["","","",""]'::jsonb, '침대 옆 협탁은 충전기·안경·리모컨 같은 자잘한 물건을 정리하기 좋다는 평이 많고, 서랍이 있어 위가 깔끔하게 유지된다는 의견이 많아요.', '["2단 서랍 수납","원목 톤 인테리어","침대 옆 적정 높이"]'::jsonb, '[0,10,20,30]'::jsonb),
  ('p18', 'nightstand', '코시나 스텐 미니 협탁 3단', 18630, 8000, 4.4, 177, '스텐 소재의 작은 3단 협탁이에요', '물기에 강한 스텐 소재라 침대 옆은 물론 화장대 옆에 두기도 좋아요. 작은 사이즈라 좁은 방에서도 자리를 많이 차지하지 않아요.', 'W350×D300×H550mm', '스테인리스 스틸', '["","","",""]'::jsonb, '스텐 소재 협탁은 물기나 화장품에 강해서 화장대 옆이나 욕실 근처에도 둘 수 있다는 평이 많아요. 사이즈가 작아 좁은 방에서도 부담 없다는 의견이 많아요.', '["스테인리스 방수 소재","콤팩트 사이즈","화장대·침대 옆 모두 OK"]'::jsonb, '[0,12,25,35]'::jsonb),
